import { LineChart } from '@mui/x-charts/LineChart';

export default function Crypto() {
  return (
    <LineChart
      xAxis={[
        {
          data: ['Янв', 'Фев', 'Мар', 'Апр'],
          scaleType: 'band',
        },
      ]}
      series={[
        {
          data: [120, 190, 300, 250],
          label: 'Продажи',
        },
      ]}
      width={500}
      height={300}
    />
  );
}
